import React from 'react';

// --- MAIN MENU COMPONENT ---
export default function Menu() {
  // Replace this list with your actual data
  const items = [
    { id: 1, name: "Sample Dish" },
    { id: 2, name: "Another Dish" }
  ];

  return (
    <section className="menu-section">
      <h1>Our Menu</h1>
      
      {items.map((item) => (
        <div key={item.id}>
          <p>{item.name}</p>
        </div>
      ))}

      {/* This is a sub-component being called */}
      <OfficeLunchSection />
    </section>
  );
}

// --- LUNCH COMPONENT ---
// We use a regular function here so it doesn't conflict with the default export
function Lunch() {
  return (
    <div className="lunch-container">
      <h2>Lunch Special</h2>
      <p>Delicious mid-day meals!</p>
    </div>
  );
}

// --- SUB-COMPONENTS (Optional) ---
function OfficeLunchSection() {
  return (
    <div>
      <h3>Office Lunch Options</h3>
    </div>
  );
}

// --- EXPORTS ---
// Since Menu is the "export default" at the top, 
// we export Lunch as a "Named Export" here:
export { Lunch };
